/**
 * generate-3m-ai-analysis.js
 * - input:  results/compare-3m-all.csv  (generated by build-3m-table.js)
 * - output: results/compare-3m-ai.md    (markdown for GitHub Job Summary)
 *
 * Env:
 *  - OPENAI_API_KEY (required for real AI)
 *  - OPENAI_MODEL (optional, default: gpt-4.1-mini)
 *  - OPENAI_MAX_OUTPUT_TOKENS (optional, default: 450)
 *
 * Node 18+, no deps.
 */

const fs = require("fs");
const path = require("path");

const CSV_PATH = path.join("results", "compare-3m-all.csv");
const OUT_MD = path.join("results", "compare-3m-ai.md");

const OPENAI_API_KEY = process.env.OPENAI_API_KEY || "";
const MODEL = process.env.OPENAI_MODEL || "gpt-4.1-mini";
const MAX_OUT = parseInt(process.env.OPENAI_MAX_OUTPUT_TOKENS || "450", 10);

function ensureOutDir() {
  fs.mkdirSync(path.dirname(OUT_MD), { recursive: true });
}

function writeMd(md) {
  ensureOutDir();
  fs.writeFileSync(OUT_MD, md, "utf-8");
}

function parseCsv(csvText) {
  // Simple CSV parser for our generated CSV (no newlines inside fields).
  // Assumes first line is header.
  const lines = csvText.split(/\r?\n/).filter(Boolean);
  if (lines.length < 2) return [];

  const header = splitCsvLine(lines[0]);
  const rows = [];

  for (let i = 1; i < lines.length; i++) {
    const cols = splitCsvLine(lines[i]);
    const obj = {};
    for (let j = 0; j < header.length; j++) obj[header[j]] = cols[j] ?? "";
    rows.push(obj);
  }
  return rows;
}

function splitCsvLine(line) {
  // Handles commas + quoted fields.
  const out = [];
  let cur = "";
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      const next = line[i + 1];
      if (inQuotes && next === '"') {
        cur += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === "," && !inQuotes) {
      out.push(cur);
      cur = "";
    } else {
      cur += ch;
    }
  }
  out.push(cur);
  return out;
}

function toNum(v) {
  if (v === null || v === undefined) return null;
  const s = String(v).trim();
  if (!s) return null;
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

function avg(nums) {
  const arr = nums.filter((n) => typeof n === "number" && Number.isFinite(n));
  if (!arr.length) return null;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function median(nums) {
  const arr = nums.filter((n) => typeof n === "number" && Number.isFinite(n)).sort((a, b) => a - b);
  if (!arr.length) return null;
  const mid = Math.floor(arr.length / 2);
  return arr.length % 2 ? arr[mid] : (arr[mid - 1] + arr[mid]) / 2;
}

function pct(n) {
  // already 0-100 in csv
  return typeof n === "number" ? Math.round(n) : null;
}

function fmtDelta(n, digits = 0) {
  if (typeof n !== "number") return "N/A";
  const sign = n > 0 ? "+" : "";
  return `${sign}${n.toFixed(digits)}`;
}

function fmtNum(n, digits = 0) {
  if (typeof n !== "number") return "N/A";
  return n.toFixed(digits);
}

function fmtSec(n) {
  if (typeof n !== "number") return "N/A";
  return `${n.toFixed(2)}s`;
}

function groupByDevice(rows) {
  const m = new Map();
  for (const r of rows) {
    const d = (r.device || "unknown").toLowerCase();
    if (!m.has(d)) m.set(d, []);
    m.get(d).push(r);
  }
  return m;
}

function buildStats(rows) {
  // expects numeric fields:
  // perf_now, perf_past, perf_delta
  // a11y_*, bp_*, seo_*
  // lcp_sec_*, cls_*
  const perfNow = rows.map((r) => toNum(r.perf_now)).filter((n) => n != null);
  const perfPast = rows.map((r) => toNum(r.perf_past)).filter((n) => n != null);
  const perfDelta = rows.map((r) => toNum(r.perf_delta)).filter((n) => n != null);

  const lcpNow = rows.map((r) => toNum(r.lcp_sec_now)).filter((n) => n != null);
  const lcpPast = rows.map((r) => toNum(r.lcp_sec_past)).filter((n) => n != null);
  const lcpDelta = rows.map((r) => toNum(r.lcp_sec_delta)).filter((n) => n != null);

  const clsNow = rows.map((r) => toNum(r.cls_now)).filter((n) => n != null);
  const clsPast = rows.map((r) => toNum(r.cls_past)).filter((n) => n != null);
  const clsDelta = rows.map((r) => toNum(r.cls_delta)).filter((n) => n != null);

  const a11yDelta = rows.map((r) => toNum(r.a11y_delta)).filter((n) => n != null);
  const bpDelta = rows.map((r) => toNum(r.bp_delta)).filter((n) => n != null);
  const seoDelta = rows.map((r) => toNum(r.seo_delta)).filter((n) => n != null);

  return {
    count: rows.length,
    perf: {
      pastAvg: avg(perfPast),
      nowAvg: avg(perfNow),
      deltaAvg: avg(perfDelta),
      nowMedian: median(perfNow),
    },
    lcp: {
      pastAvg: avg(lcpPast),
      nowAvg: avg(lcpNow),
      deltaAvg: avg(lcpDelta),
      nowMedian: median(lcpNow),
    },
    cls: {
      pastAvg: avg(clsPast),
      nowAvg: avg(clsNow),
      deltaAvg: avg(clsDelta),
      nowMedian: median(clsNow),
    },
    other: {
      a11yDeltaAvg: avg(a11yDelta),
      bpDeltaAvg: avg(bpDelta),
      seoDeltaAvg: avg(seoDelta),
    },
  };
}

function topMovers(rows, keyDelta, n, direction /* "up" | "down" */) {
  const scored = rows
    .map((r) => ({ r, d: toNum(r[keyDelta]) }))
    .filter((x) => typeof x.d === "number");

  scored.sort((a, b) => a.d - b.d); // ascending

  if (direction === "up") scored.reverse(); // descending
  const top = scored.slice(0, n).map((x) => x.r);
  return top;
}

function pickActionHints(statsAll) {
  // basic heuristic suggestions based on regressions
  const hints = [];

  if (typeof statsAll.lcp.deltaAvg === "number" && statsAll.lcp.deltaAvg > 0.2) {
    hints.push("LCP가 전반적으로 악화 → hero 이미지/폰트/critical CSS, 서버 TTFB, render-blocking 리소스 점검");
  }
  if (typeof statsAll.cls.deltaAvg === "number" && statsAll.cls.deltaAvg > 0.02) {
    hints.push("CLS가 전반적으로 악화 → 이미지/광고 영역 고정, 폰트 swap 전략, 레이아웃 변동 요소 점검");
  }
  if (typeof statsAll.perf.deltaAvg === "number" && statsAll.perf.deltaAvg < -3) {
    hints.push("Performance 평균이 하락 → JS 번들 증가/3rd-party 스크립트/장기 캐시 정책 변화 여부 확인");
  }

  if (!hints.length) {
    hints.push("전반적으로 큰 회귀는 없어 보임 → 악화 Top URL 위주로 원인 추적 & 개선 영향이 큰 구간부터 처리");
  }
  return hints.slice(0, 3);
}

function buildAiPrompt(payload) {
  // payload is compact summary + top movers lists
  return `
너는 웹 성능(특히 Lighthouse/Core Web Vitals) 분석 전문가야.
아래는 "3개월 전 vs 현재" 비교 결과를 요약한 데이터야.

요청:
1) 가장 많이 개선된 지표/패턴(왜 개선됐을 가능성이 큰지 가설 포함)
2) 가장 아쉬운(악화된) 지표/패턴 + 위험도
3) 팀이 바로 실행할 수 있는 추천 액션 Top 3 (우선순위/효과/난이도 기준)
4) "추가로 확인하면 좋은 것" 2개 (데이터/측정 관점)

출력 형식(마크다운):
## TL;DR
- ...
## Improvements
- ...
## Regressions / Risks
- ...
## Recommended actions (Top 3)
1. ...
2. ...
3. ...
## What to check next
- ...
- ...

데이터:
${JSON.stringify(payload, null, 2)}
`.trim();
}

async function callOpenAI(prompt) {
  // Uses Responses API
  const res = await fetch("https://api.openai.com/v1/responses", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${OPENAI_API_KEY}`,
    },
    body: JSON.stringify({
      model: MODEL,
      max_output_tokens: Number.isFinite(MAX_OUT) ? MAX_OUT : 450,
      input: prompt,
    }),
  });

  const json = await res.json();

  if (!res.ok) {
    const msg = json?.error?.message || `HTTP ${res.status}`;
    throw new Error(msg);
  }

  // robust extraction
  const text =
    json?.output?.[0]?.content?.find((c) => c.type === "output_text")?.text ||
    json?.output?.[0]?.content?.[0]?.text ||
    "";

  if (!text) throw new Error("Empty AI response");
  return text;
}

function buildFallbackMd(rows, statsAll, statsByDevice) {
  // if no key or API failure
  const hints = pickActionHints(statsAll);

  const deviceLines = [];
  for (const [dev, st] of statsByDevice.entries()) {
    deviceLines.push(
      `- **${dev.toUpperCase()}** Perf avg: ${fmtNum(st.perf.nowAvg, 1)} (${fmtDelta(st.perf.deltaAvg, 1)}), ` +
        `LCP avg: ${fmtSec(st.lcp.nowAvg)} (${fmtDelta(st.lcp.deltaAvg, 2)}s), ` +
        `CLS avg: ${fmtNum(st.cls.nowAvg, 3)} (${fmtDelta(st.cls.deltaAvg, 3)})`
    );
  }

  return `
## TL;DR
- (AI 호출 실패/미설정) 3개월 비교 요약만 표시합니다.
- 전체 URL 수: **${rows.length}**

## Summary (All)
- Perf avg: ${fmtNum(statsAll.perf.nowAvg, 1)} (${fmtDelta(statsAll.perf.deltaAvg, 1)})
- LCP avg: ${fmtSec(statsAll.lcp.nowAvg)} (${fmtDelta(statsAll.lcp.deltaAvg, 2)}s)
- CLS avg: ${fmtNum(statsAll.cls.nowAvg, 3)} (${fmtDelta(statsAll.cls.deltaAvg, 3)})

## By Device
${deviceLines.join("\n")}

## Recommended actions (Top 3)
${hints.map((h, i) => `${i + 1}. ${h}`).join("\n")}
`.trim();
}

function compactRow(r) {
  // keep only what is needed for AI
  return {
    device: r.device,
    url: r.url,
    perf: { past: toNum(r.perf_past), now: toNum(r.perf_now), delta: toNum(r.perf_delta) },
    a11y: { delta: toNum(r.a11y_delta) },
    bp: { delta: toNum(r.bp_delta) },
    seo: { delta: toNum(r.seo_delta) },
    lcp: { past: toNum(r.lcp_sec_past), now: toNum(r.lcp_sec_now), delta: toNum(r.lcp_sec_delta) },
    cls: { past: toNum(r.cls_past), now: toNum(r.cls_now), delta: toNum(r.cls_delta) },
  };
}

async function main() {
  // Always create an md output so subsequent steps don't fail
  if (!exists(CSV_PATH)) {
    writeMd(
      `## 3-Month AI Insights\n\n_(No comparison CSV found at \`${CSV_PATH}\`. Run build-3m-table.js first.)_\n`
    );
    console.log("No CSV. Wrote placeholder md.");
    return;
  }

  const csv = fs.readFileSync(CSV_PATH, "utf-8");
  const rows = parseCsv(csv);

  if (!rows.length) {
    writeMd("## 3-Month AI Insights\n\n_(Comparison CSV is empty.)_\n");
    console.log("Empty CSV. Wrote placeholder md.");
    return;
  }

  // Determine if we actually have past data (any perf_past present)
  const hasPast = rows.some((r) => String(r.perf_past || "").trim() !== "");
  if (!hasPast) {
    // Still write something useful
    const statsAll = buildStats(rows);
    const statsByDevice = groupByDevice(rows);
    const statsByDeviceComputed = new Map();
    for (const [dev, arr] of statsByDevice.entries()) statsByDeviceComputed.set(dev, buildStats(arr));

    writeMd(buildFallbackMd(rows, statsAll, statsByDeviceComputed));
    console.log("No past data yet. Wrote summary md.");
    return;
  }

  // Compute stats and top movers to keep prompt small/cheap
  const statsAll = buildStats(rows);
  const grouped = groupByDevice(rows);
  const statsByDevice = new Map();
  for (const [dev, arr] of grouped.entries()) statsByDevice.set(dev, buildStats(arr));

  const topImprovePerf = topMovers(rows, "perf_delta", 5, "up").map(compactRow);
  const topRegressPerf = topMovers(rows, "perf_delta", 5, "down").map(compactRow);

  const topRegressLCP = topMovers(rows, "lcp_sec_delta", 5, "up").map(compactRow); // LCP delta up = worse
  const topRegressCLS = topMovers(rows, "cls_delta", 5, "up").map(compactRow); // CLS delta up = worse

  const payload = {
    meta: {
      rows: rows.length,
      model: MODEL,
      note: "All scores are Lighthouse category scores (0-100). LCP is seconds, CLS is raw.",
    },
    statsAll: {
      perf: {
        pastAvg: statsAll.perf.pastAvg,
        nowAvg: statsAll.perf.nowAvg,
        deltaAvg: statsAll.perf.deltaAvg,
        nowMedian: statsAll.perf.nowMedian,
      },
      lcp: {
        pastAvg: statsAll.lcp.pastAvg,
        nowAvg: statsAll.lcp.nowAvg,
        deltaAvg: statsAll.lcp.deltaAvg,
        nowMedian: statsAll.lcp.nowMedian,
      },
      cls: {
        pastAvg: statsAll.cls.pastAvg,
        nowAvg: statsAll.cls.nowAvg,
        deltaAvg: statsAll.cls.deltaAvg,
        nowMedian: statsAll.cls.nowMedian,
      },
      otherDeltaAvg: {
        a11y: statsAll.other.a11yDeltaAvg,
        bp: statsAll.other.bpDeltaAvg,
        seo: statsAll.other.seoDeltaAvg,
      },
    },
    byDevice: Object.fromEntries(
      [...statsByDevice.entries()].map(([dev, st]) => [
        dev,
        {
          count: st.count,
          perf: { pastAvg: st.perf.pastAvg, nowAvg: st.perf.nowAvg, deltaAvg: st.perf.deltaAvg },
          lcp: { pastAvg: st.lcp.pastAvg, nowAvg: st.lcp.nowAvg, deltaAvg: st.lcp.deltaAvg },
          cls: { pastAvg: st.cls.pastAvg, nowAvg: st.cls.nowAvg, deltaAvg: st.cls.deltaAvg },
        },
      ])
    ),
    topMovers: {
      perfImproved: topImprovePerf,
      perfRegressed: topRegressPerf,
      lcpRegressed: topRegressLCP,
      clsRegressed: topRegressCLS,
    },
  };

  // If no API key, write fallback
  if (!OPENAI_API_KEY) {
    writeMd(buildFallbackMd(rows, statsAll, statsByDevice));
    console.log("No OPENAI_API_KEY. Wrote fallback md.");
    return;
  }

  try {
    const prompt = buildAiPrompt(payload);
    const aiMd = await callOpenAI(prompt);
    writeMd(aiMd.trim() + "\n");
    console.log(`✅ Wrote AI analysis: ${OUT_MD}`);
  } catch (err) {
    console.error("AI analysis failed:", err?.message || err);
    writeMd(buildFallbackMd(rows, statsAll, statsByDevice));
    console.log("Wrote fallback md due to AI failure.");
  }
}

main();
